item.description:
A. 愤怒的牛 题目连接：Reach-Top
考虑二分两只牛之间的最小距离，然后用贪心放置牛的位置。
#include &lt;bits/stdc++.h&gt; using namespace std; const int N = 1e5 + 5; int n, m; int a[N]; bool check(int len) { int cnt = 1, last = a[1]; for (int i = 2; i &lt;= n; i++) { if (a[i] - last &gt;= len) { cnt++; last = a[i]; } } return cnt &gt;= m; } int main() { scanf(&#34;%d%d&#34;, &amp;n, &amp;m); for (int i = 1; i &lt;= n; i++) { scanf(&#34;%d&#34;, &amp;a[i]); } sort(a + 1, a + 1 + n); int low = 0, high = 1e9, ans = 1e9; while (low &lt;= high) { int mid = (low + high) / 2; if (check(mid)) { ans = mid; low = mid + 1; } else { high = mid - 1; } } printf(&#34;%d\n&#34;, ans); } B.
